-- 월요일 윈도우의 지속 시간을 6시간으로 변경
BEGIN
  DBMS_SCHEDULER.SET_ATTRIBUTE(
    name      => 'MONDAY_WINDOW',
    attribute => 'DURATION',
    value     => NUMTODSINTERVAL(6, 'HOUR')
  );
END;
/

-- 월요일 윈도우의 시작 시간을 23:00으로 변경
BEGIN
  DBMS_SCHEDULER.SET_ATTRIBUTE(
    name      => 'MONDAY_WINDOW',
    attribute => 'REPEAT_INTERVAL',
    value     => 'FREQ=WEEKLY;BYDAY=MON;BYHOUR=23;BYMINUTE=0;BYSECOND=0'
  );
END;
/

-- SQL Tuning Advisor를 모든 윈도우에서 비활성화
BEGIN
  DBMS_AUTO_TASK_ADMIN.DISABLE(
    client_name => 'sql tuning advisor',
    operation   => NULL,
    window_name => NULL
  );
END;
/

-- SQL Tuning Advisor를 토요일 윈도우에서만 활성화
BEGIN
  DBMS_AUTO_TASK_ADMIN.ENABLE(
    client_name => 'sql tuning advisor',
    operation   => NULL,
    window_name => 'SATURDAY_WINDOW'
  );
END;
/

BEGIN
  DBMS_RESOURCE_MANAGER.CREATE_PENDING_AREA;

  -- Resource Plan 생성
  DBMS_RESOURCE_MANAGER.CREATE_PLAN(
    plan    => 'MY_DAYTIME_PLAN',
    comment => 'Daytime resource plan for OLTP priority'
  );

  -- Consumer Group 생성
  DBMS_RESOURCE_MANAGER.CREATE_CONSUMER_GROUP(
    consumer_group => 'OLTP_GROUP',
    comment        => 'OLTP workload group'
  );

  DBMS_RESOURCE_MANAGER.CREATE_CONSUMER_GROUP(
    consumer_group => 'REPORT_GROUP',
    comment        => 'Reporting workload group'
  );

  -- Plan Directive 생성
  DBMS_RESOURCE_MANAGER.CREATE_PLAN_DIRECTIVE(
    plan             => 'MY_DAYTIME_PLAN',
    group_or_subplan => 'OLTP_GROUP',
    mgmt_p1          => 70,
    parallel_degree_limit_p1 => 4
  );

  DBMS_RESOURCE_MANAGER.CREATE_PLAN_DIRECTIVE(
    plan             => 'MY_DAYTIME_PLAN',
    group_or_subplan => 'REPORT_GROUP',
    mgmt_p1          => 20,
    parallel_degree_limit_p1 => 8,
    switch_time      => 300,
    switch_group     => 'OTHER_GROUPS'
  );

  DBMS_RESOURCE_MANAGER.CREATE_PLAN_DIRECTIVE(
    plan             => 'MY_DAYTIME_PLAN',
    group_or_subplan => 'OTHER_GROUPS',
    mgmt_p1          => 10
  );

  DBMS_RESOURCE_MANAGER.SUBMIT_PENDING_AREA;
END;
/

BEGIN
  DBMS_RESOURCE_MANAGER.CREATE_PENDING_AREA;

  DBMS_RESOURCE_MANAGER.CREATE_CDB_PLAN(
    plan    => 'MY_CDB_PLAN',
    comment => 'CDB-level resource plan for PDB management'
  );

  -- 운영 PDB: 높은 리소스 할당
  DBMS_RESOURCE_MANAGER.CREATE_CDB_PLAN_DIRECTIVE(
    plan                  => 'MY_CDB_PLAN',
    pluggable_database    => 'PROD_PDB',
    shares                => 4,
    utilization_limit     => 80,
    parallel_server_limit => 60,
    max_iops              => 0,
    max_mbps              => 0
  );

  -- 개발 PDB: 제한된 리소스 할당
  DBMS_RESOURCE_MANAGER.CREATE_CDB_PLAN_DIRECTIVE(
    plan                  => 'MY_CDB_PLAN',
    pluggable_database    => 'DEV_PDB',
    shares                => 1,
    utilization_limit     => 30,
    parallel_server_limit => 20,
    max_iops              => 5000,
    max_mbps              => 200
  );

  -- Default directive for unlisted PDBs
  DBMS_RESOURCE_MANAGER.UPDATE_CDB_DEFAULT_DIRECTIVE(
    plan                  => 'MY_CDB_PLAN',
    new_shares            => 1,
    new_utilization_limit => 20
  );

  DBMS_RESOURCE_MANAGER.SUBMIT_PENDING_AREA;
END;
/

-- CDB Resource Plan 활성화
ALTER SYSTEM SET RESOURCE_MANAGER_PLAN = 'MY_CDB_PLAN';

-- 유지관리 윈도우에 커스텀 Resource Plan 연결
BEGIN
  DBMS_SCHEDULER.SET_ATTRIBUTE(
    name      => 'MONDAY_WINDOW',
    attribute => 'RESOURCE_PLAN',
    value     => 'MY_MAINTENANCE_PLAN'
  );
END;
/

-- Resource Plan 전환 없이 윈도우만 사용 (빈 문자열)
BEGIN
  DBMS_SCHEDULER.SET_ATTRIBUTE(
    name      => 'TUESDAY_WINDOW',
    attribute => 'RESOURCE_PLAN',
    value     => ''
  );
END;
/

-- Resource Manager 수동 활성화
ALTER SYSTEM SET RESOURCE_MANAGER_PLAN = 'DEFAULT_PLAN';

-- Resource Manager 비활성화 (Maintenance Window 자동 전환은 유지)
ALTER SYSTEM SET RESOURCE_MANAGER_PLAN = '';

-- Resource Manager 완전 비활성화 (Maintenance Window 자동 전환도 차단)
ALTER SYSTEM SET RESOURCE_MANAGER_PLAN = '' FORCE;

-- 유지관리 윈도우 수동 열기 (즉시 실행)
BEGIN
  DBMS_SCHEDULER.OPEN_WINDOW(
    window_name => 'MONDAY_WINDOW',
    duration    => NUMTODSINTERVAL(2, 'HOUR'),
    force       => FALSE
  );
END;
/

-- 유지관리 윈도우 수동 닫기
BEGIN
  DBMS_SCHEDULER.CLOSE_WINDOW(
    window_name => 'MONDAY_WINDOW'
  );
END;
/
